const result = $json.ingredient_result;
const errors = [];
const warnings = [];

const allowedUnits = ["lb", "oz", "cup", "tbsp", "tsp", "count", "bunch"];
const allowedRoles = ["protein", "base", "produce", "dairy", "pantry", "fresh", "brightness", "herb", "sauce", "texture", "spice"];

if (!$json.valid_json) {
  return [{ json: $json }];
}

if (!result || typeof result !== "object") {
  errors.push("ingredient_result missing");
}

if (!Array.isArray(result.ingredients) || result.ingredients.length === 0) {
  errors.push("ingredients missing or empty");
} else {
  result.ingredients.forEach((item, idx) => {
    if (!item.item || typeof item.item !== "string") {
      errors.push(`ingredient ${idx} item missing or invalid`);
    }
    if (typeof item.amount !== "number") {
      errors.push(`ingredient ${idx} amount missing or invalid`);
    }
    if (!item.unit || typeof item.unit !== "string") {
      errors.push(`ingredient ${idx} unit missing or invalid`);
    } else if (!allowedUnits.includes(item.unit)) {
      errors.push(`ingredient ${idx} unit not allowed`);
    }

    if (!item.role || typeof item.role !== "string") {
      errors.push(`ingredient ${idx} role missing or invalid`);
    } else if (!allowedRoles.includes(item.role)) {
      errors.push(`ingredient ${idx} role not allowed`);
    }
  });

  const roles = result.ingredients.map(i => i.role);

  if (!roles.includes("protein")) {
    errors.push("ingredients must include a protein role");
  }

  if (!roles.includes("fresh") && !roles.includes("brightness") && !roles.includes("herb")) {
    warnings.push("ingredient list may lack freshness or brightness");
  }

  if (result.ingredients.length < 4) {
    warnings.push("ingredient list may be too small for an elevated recipe");
  }

  if (result.ingredients.length > 12) {
    warnings.push("ingredient list may be too long");
  }
}

if (errors.length > 0) {
  return [
    {
      json: {
        ...$json,
        valid: false,
        errors,
        warnings
      }
    }
  ];
}

return [
  {
    json: {
      ...$json,
      valid: true,
      warnings,
      recipe: {
        ...$json.recipe,
        ingredients: result.ingredients
      }
    }
  }
];
